    identifier = p.token_next_by(i=Identifier)
except Exception:
    identifier = None

# If token is a punctuation/operator ending, use the previous keyword
token_value = getattr(token, "value", token)
if isinstance(token_value, str):
    token_value = token_value.lower()

if token_value.endswith(",") or token_value.endswith("(") or token_value in ("=", "and", "or", "+", "-", "*", "/"):
    prev_keyword, new_text_before_cursor = find_prev_keyword(text_before_cursor)
    if prev_keyword:
        return suggest_based_on_last_token(prev_keyword, new_text_before_cursor, full_text, identifier)
    return [{"type": "keyword"}, {"type": "special"}]

return suggest_based_on_last_token(token, text_before_cursor, full_text, identifier)

