# If it's already an IPv4-mapped IPv6 address, leave it as-is.
if hostname.startswith("::ffff:"):
    return hostname

# Convert plain IPv6 addresses to IPv4-mapped IPv6 format when possible.
if has_ipv6:
    try:
        import ipaddress

        ip = ipaddress.ip_address(hostname)
        if ip.version == 6:
            # If it's an IPv4-mapped IPv6 address, normalize to ::ffff:x.x.x.x
            if ip.ipv4_mapped is not None:
                return f"::ffff:{ip.ipv4_mapped}"
            # If it's a pure IPv6 address, keep it unchanged unless it is
            # an IPv4-compatible style address that can be represented as IPv4.
            if ip.packed[:12] == b"\x00" * 12:
                return f"::ffff:{ipaddress.IPv4Address(ip.packed[12:])}"
    except Exception:
        pass

return hostname

