# Helper to estimate the size of a character class from the pattern text.
def _char_class_size(p):
    if "\\d" in p:
        return char_class_bases["digit"]
    if "\\w" in p:
        return char_class_bases["alphanumeric"]
    if "\\s" in p:
        return 33
    if "[a-z]" in p or "[A-Za-z]" in p:
        return char_class_bases["alpha"]
    return char_class_bases["unicode"]

