expanded = [[]]

for recipe_name in recipes:
    recipe = Recipe.get_recipe(recipe_name, ctx)

    # Build the list of possible choices for this recipe:
    # - if it has alternative dependencies, each alternative becomes a branch
    # - otherwise, the recipe itself is the only choice
    choices = []
    has_alternatives = False
    for dep in recipe.depends:
        if isinstance(dep, (tuple, list)):
            has_alternatives = True
            choices.append(list(dep))
        else:
            choices.append([dep])

    # If there are no dependencies, keep the recipe itself as the only item
    if not choices:
        choices = [[recipe_name]]

    # Expand current combinations with all dependency choices
    new_expanded = []
    for combo in expanded:
        # Start with the recipe itself in every combination
        base_combo = combo + [recipe_name]

        # Generate all combinations of dependency alternatives
        combos_for_recipe = [[]]
        for choice_group in choices:
            combos_for_group = []
            for partial in combos_for_recipe:
                for choice in choice_group:
                    if choice not in partial:
                        combos_for_group.append(partial + [choice])
                    else:
                        combos_for_group.append(partial)
            combos_for_recipe = combos_for_group

        for dep_combo in combos_for_recipe:
            merged = base_combo[:]
            for dep in dep_combo:
                if dep not in merged:
                    merged.append(dep)
            new_expanded.append(merged)

    expanded = new_expanded

# Remove duplicates while preserving order
unique = []
seen = set()
for combo in expanded:
    key = tuple(combo)
    if key not in seen:
        seen.add(key)
        unique.append(combo)

return unique

