text = add_surrogate(text)

# Sort entities by start offset, and for equal starts by longer entities first.
entities.sort(key=lambda e: (e.offset, -(e.offset + e.length)))

# Build opening/closing tags at each position.
opens = {}
closes = {}

for e in entities:
    start = e.offset
    end = e.offset + e.length

    formatter = ENTITY_TO_FORMATTER.get(type(e))
    if formatter is None:
        continue

    if callable(formatter):
        open_tag, close_tag = formatter(e, text[start:end])
    else:
        open_tag, close_tag = formatter

    opens.setdefault(start, []).append(open_tag)
    closes.setdefault(end, []).insert(0, close_tag)

result = []
i = 0
n = len(text)

while i < n:
    if i in closes:
        result.extend(closes[i])

    if i in opens:
        result.extend(opens[i])

    ch = text[i]

    # Keep surrogate pairs intact.
    if within_surrogate(text, i):
        result.append(escape(text[i:i + 2]))
        i += 2
        continue

    result.append(escape(ch))
    i += 1

if n in closes:
    result.extend(closes[n])

return del_surrogate(''.join(result))

