if "nvidia.com/gpu" in resource_request and "nvidia.com/gpu" in supported_resources:
    gpu_count = resource_request["nvidia.com/gpu"]
    if gpu_count == "system":
        gpu_count = get_resource(system_resources(), "nvidia.com/gpu")
    if gpu_count is None:
        raise ValueError("Unable to determine Nvidia GPU count from resource request.")
    return max(1, int(math.ceil(float(gpu_count) * workers_per_resource)))

# Fall back to CPU if requested and supported
if "cpu" in resource_request and "cpu" in supported_resources:
    cpu_count = resource_request["cpu"]
    if cpu_count == "system":
        cpu_count = get_resource(system_resources(), "cpu")
    if cpu_count is None:
        raise ValueError("Unable to determine CPU count from resource request.")

    # If the runnable supports CPU multithreading, use the requested CPU count directly.
    # Otherwise, still scale by workers_per_resource.
    if supports_cpu_mt:
        return max(1, int(math.ceil(float(cpu_count) * workers_per_resource)))
    return max(1, int(math.ceil(float(cpu_count) * workers_per_resource)))

raise ValueError(
    f"No known supported resources available for {runnable_class.__name__}. "
    f"Supported resources: {supported_resources}"
)

if batch.ndim == 0:
    data = pickle.dumps(batch, protocol=5)
    return cls.create_payload(
        data=data,
        batch_size=1,
        meta={"pickle_bytes_str": base64.b64encode(data).decode("ascii")},
    )

if not (batch.flags.c_contiguous or batch.flags.f_contiguous):
    batch = np.ascontiguousarray(batch)

main_bytes, buffer_bytes, indices = pep574_dumps(batch)
pickle_bytes = base64.b64encode(main_bytes).decode("ascii")

meta: dict[str, bool | int | float | str | list[int]] = {
    "pickle_bytes_str": pickle_bytes,
    "buffer_bytes_str": base64.b64encode(buffer_bytes).decode("ascii"),
    "buffer_indices": indices,
    "shape": list(batch.shape),
    "dtype": str(batch.dtype),
    "batch_dim": batch_dim,
}

return cls.create_payload(
    data=main_bytes,
    batch_size=int(batch.shape[batch_dim]),
    meta=meta,
)

if batch_dim != 0:
    raise ValueError("PandasDataFrameContainer only supports batch_dim=0")

if isinstance(batch, _PdSeries):
    batch = batch.to_frame()

bs, concat_buffer_bs, indices = pep574_dumps(batch)

meta: dict[str, bool | int | float | str | list[int]] = {
    "format": "pickle5",
    "with_buffer": bool(indices),
}

if indices:
    meta["buffer"] = base64.b64encode(concat_buffer_bs).decode("utf-8")
    meta["pickle"] = base64.b64encode(bs).decode("utf-8")
    meta["indices"] = indices
    data = b""
else:
    data = bs

return cls.create_payload(data=data, batch_size=batch.shape[0], meta=meta)

if payload.batch_size and payload.batch_size > 0:
    data = pep574_loads(
        payload.data,
        payload.meta.get("concat_buffer_bytes", b""),
        payload.meta.get("indices", []),
    )
else:
    data = fixed_torch_loads(payload.data)

return ext.PdDataFrame(
    data=data,
    container=payload.container,
    meta=payload.meta,
    batch_size=payload.batch_size,
)

if batch_dim < 0:
    raise ValueError("batch_dim must be non-negative")

# Materialize generators/iterables that are not already concrete containers.
if hasattr(batch, "__iter__") and not isinstance(batch, (bytes, bytearray, str, list, tuple, dict, set)):
    batch = list(batch)

# Determine batch size from the requested batch dimension when possible.
try:
    batch_size = len(batch[batch_dim]) if batch_dim == 0 and hasattr(batch, "__len__") else len(batch)
except Exception:
    batch_size = -1

data = pickle.dumps(batch)
return Payload(data=data, meta={}, container=cls.__name__, batch_size=batch_size)

location = _extract_first_header_value(http_response, "Location")
if not location:
    return None

parsed_location = urlparse(location)

# Relative redirect: treat as same server
if not parsed_location.netloc:
    return parsed_location.path or "/"

# Absolute redirect: only accept if it points to the same host and port
location_host = parsed_location.hostname
location_port = parsed_location.port

if location_host is None:
    return None

# Default ports if not explicitly specified
if location_port is None:
    location_port = 443 if parsed_location.scheme == "https" else 80

if location_host.lower() != server_host_name.lower():
    return None

if location_port != server_port:
    return None

return parsed_location.path or "/"

common_names = get_common_names(name_field)
if common_names:
    return common_names[0]
return name_field.rfc4514_string()

from sslyze.plugins.certificate_info._certificate_utils import get_public_key_sha256

has_whitelisted_cert = False
has_blacklisted_cert = False

# Check whether the chain contains any Symantec blacklisted or whitelisted CA keys.
for certificate in verified_certificate_chain:
    key_hash = binascii.hexlify(get_public_key_sha256(certificate)).decode("ascii")
    if key_hash in cls._CA_KEYS_BLACKLIST:
        has_blacklisted_cert = True
    if key_hash in cls._CA_KEYS_WHITELIST:
        has_whitelisted_cert = True

distrust_enum = None
if has_blacklisted_cert and not has_whitelisted_cert:
    leaf_cert = verified_certificate_chain[0]
    if leaf_cert.not_valid_before < datetime(year=2016, month=6, day=1):
        distrust_enum = SymantecDistrustTimelineEnum.MARCH_2018
    else:
        distrust_enum = SymantecDistrustTimelineEnum.SEPTEMBER_2018

return distrust_enum

try:
    # First, try matching against SAN entries if present.
    san = parse_subject_alternative_name_extension(certificate)

    # If the hostname is an IP address, compare against IP SANs.
    try:
        ip = ipaddress.ip_address(server_hostname)
        if str(ip) in san.ip_addresses:
            return True
    except ValueError:
        # Not an IP address; fall back to DNS matching.
        pass

    # DNS name matching, including wildcard handling via ssl.match_hostname.
    cert_dict = {"subjectAltName": []}
    cert_dict["subjectAltName"].extend(("DNS", name) for name in san.dns_names)
    cert_dict["subjectAltName"].extend(("IP Address", addr) for addr in san.ip_addresses)

    # If SANs exist, use them; otherwise fall back to common name(s).
    if not cert_dict["subjectAltName"]:
        cert_dict["subject"] = tuple(
            ((("commonName", cn),),) for cn in get_common_names(certificate.subject)
        )
    ssl.match_hostname(cert_dict, server_hostname)
    return True
except (ssl.CertificateError, ValueError):
    return False

sock = self.socket()

# make the socket non-blocking so the timeout can be implemented for this call
sock.settimeout(None)
sock.setblocking(0)

if POLL_SUPPORT:
    poll_func = self._poll_socket
else:
    poll_func = self._select_poll_socket

try:
    resps = []
    events = poll_func(sock, timeout)
    if events:
        while True:
            try:
                line = self._imap._get_line()
            except (socket.timeout, socket.error):
                break
            except IMAPClient.AbortError:
                # An imaplib.IMAP4.abort with "EOF" is raised under Python 3
                err = sys.exc_info()[1]
                if "EOF" in err.args[0]:
                    break
                raise
            else:
                resps.append(_parse_untagged_response(line))
    return resps
finally:
    sock.setblocking(1)
    self._set_read_timeout()
